 44→    options.UseNpgsql(npgsql =>
 45→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "catalog"));
 46→    options.UseSnakeCaseNamingConvention();
 47→    options.AddInterceptors(softDeleteInterceptor, concurrencyInterceptor, auditInterceptor);
 48→});
