 50→builder.AddNpgsqlDbContext<CartDbContext>("appdb", configureDbContextOptions: options =>
 51→{
 52→    options.UseNpgsql(npgsql =>
 53→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "cart"));
 54→    options.UseSnakeCaseNamingConvention();
 55→    options.AddInterceptors(softDeleteInterceptor, concurrencyInterceptor, auditInterceptor);
 56→});
 57→
 58→builder.AddNpgsqlDbContext<OrderingDbContext>("appdb", configureDbContextOptions: options =>
 59→{
 60→    options.UseNpgsql(npgsql =>
 61→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "ordering"));
 62→    options.UseSnakeCaseNamingConvention();
 63→    options.AddInterceptors(softDeleteInterceptor, concurrencyInterceptor, auditInterceptor);
 64→});
 65→
 66→builder.AddNpgsqlDbContext<InventoryDbContext>("appdb", configureDbContextOptions: options =>
 67→{
 68→    options.UseNpgsql(npgsql =>
 69→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "inventory"));
 70→    options.UseSnakeCaseNamingConvention();
 71→    options.AddInterceptors(softDeleteInterceptor, concurrencyInterceptor, auditInterceptor);
 72→});
 73→
 74→builder.AddNpgsqlDbContext<ProfilesDbContext>("appdb", configureDbContextOptions: options =>
 75→{
 76→    options.UseNpgsql(npgsql =>
 77→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "profiles"));
 78→    options.UseSnakeCaseNamingConvention();
 79→    options.AddInterceptors(softDeleteInterceptor, concurrencyInterceptor, auditInterceptor);
 80→});
 81→
 82→builder.AddNpgsqlDbContext<ReviewsDbContext>("appdb", configureDbContextOptions: options =>
 83→{
 84→    options.UseNpgsql(npgsql =>
 85→        npgsql.MigrationsHistoryTable("__EFMigrationsHistory", "reviews"));
 86→    options.UseSnakeCaseNamingConvention();
