221→// MediatR with validation pipeline
222→builder.Services.AddMediatR(cfg =>
223→{
224→    cfg.RegisterServicesFromAssemblyContaining<Program>();
225→
226→    // Validation runs first - fail fast before handler executes
227→    cfg.AddOpenBehavior(typeof(ValidationBehavior<,>));
228→
229→    // Result validation: returns Result.Fail for Result-typed handlers (coexists with ValidationBehavior)
230→    cfg.AddOpenBehavior(typeof(ResultValidationBehavior<,>));
231→});
232→
233→// FluentValidation - auto-discover validators
234→builder.Services.AddValidatorsFromAssemblyContaining<Program>();
235→
236→// Catalog services
