 47→    public static TBuilder ConfigureOpenTelemetry<TBuilder>(this TBuilder builder)
 48→        where TBuilder : IHostApplicationBuilder
 49→    {
 50→        builder.Logging.AddOpenTelemetry(logging =>
 51→        {
 52→            logging.IncludeFormattedMessage = true;
 53→            logging.IncludeScopes = true;
 54→        });
 55→
 56→        builder.Services.AddOpenTelemetry()
 57→            .WithMetrics(metrics =>
 58→            {
 59→                metrics.AddAspNetCoreInstrumentation()
 60→                    .AddHttpClientInstrumentation()
 61→                    .AddRuntimeInstrumentation();
 62→            })
 63→            .WithTracing(tracing =>
 64→            {
 65→                tracing.AddSource(builder.Environment.ApplicationName)
 66→                    .AddSource(MassTransit.Logging.DiagnosticHeaders.DefaultListenerName)
 67→                    .AddAspNetCoreInstrumentation(tracing =>
 68→                        // Exclude health check requests from tracing
 69→                        tracing.Filter = context =>
 70→                            !context.Request.Path.StartsWithSegments(HealthEndpointPath)
 71→                            && !context.Request.Path.StartsWithSegments(AlivenessEndpointPath)
 72→                    )
 73→                    // Uncomment the following line to enable gRPC instrumentation (requires the OpenTelemetry.Instrumentation.GrpcNetClient package)
 74→                    //.AddGrpcClientInstrumentation()
 75→                    .AddHttpClientInstrumentation();
 76→            });
 77→
 78→        builder.AddOpenTelemetryExporters();
 79→
 80→        return builder;
 81→    }
 82→
 83→    private static TBuilder AddOpenTelemetryExporters<TBuilder>(this TBuilder builder)
 84→        where TBuilder : IHostApplicationBuilder
 85→    {
 86→        var useOtlpExporter = !string.IsNullOrWhiteSpace(builder.Configuration["OTEL_EXPORTER_OTLP_ENDPOINT"]);
 87→
 88→        if (useOtlpExporter)
 89→        {
 90→            builder.Services.AddOpenTelemetry().UseOtlpExporter();
 91→        }
 92→
 93→        // Uncomment the following lines to enable the Azure Monitor exporter (requires the Azure.Monitor.OpenTelemetry.AspNetCore package)
 94→        //if (!string.IsNullOrEmpty(builder.Configuration["APPLICATIONINSIGHTS_CONNECTION_STRING"]))
 95→        //{
 96→        //    builder.Services.AddOpenTelemetry()
 97→        //       .UseAzureMonitor();
 98→        //}
 99→
100→        return builder;
101→    }
102→
103→    public static TBuilder AddDefaultHealthChecks<TBuilder>(this TBuilder builder)
104→        where TBuilder : IHostApplicationBuilder
105→    {
106→        builder.Services.AddHealthChecks()
107→            // Add a default liveness check to ensure app is responsive
108→            .AddCheck("self", () => HealthCheckResult.Healthy(), ["live"]);
109→
110→        return builder;
111→    }
112→
113→    public static WebApplication MapDefaultEndpoints(this WebApplication app)
114→    {
115→        // Health checks are always registered for K8s liveness/readiness probes.
116→        // These endpoints run on internal ClusterIP services, not publicly reachable.
117→
118→        // All health checks must pass for app to be considered ready to accept traffic after starting
119→        app.MapHealthChecks(HealthEndpointPath);
120→
121→        // Only health checks tagged with the "live" tag must pass for app to be considered alive
122→        app.MapHealthChecks(AlivenessEndpointPath, new HealthCheckOptions
123→        {
124→            Predicate = r => r.Tags.Contains("live")
125→        });
126→
127→        return app;
128→    }
129→}

  1→using System.Diagnostics;
  2→using System.Threading.RateLimiting;
  3→using Microsoft.AspNetCore.RateLimiting;
  4→
  5→var builder = WebApplication.CreateBuilder(args);
  6→
  7→builder.AddServiceDefaults();
  8→
  9→// JWT Authentication - matching ApiService configuration
 10→builder.Services.AddAuthentication()
 11→    .AddKeycloakJwtBearer(
 12→        serviceName: "keycloak",
 13→        realm: "micro-commerce",
 14→        options =>
 15→        {
 16→            options.TokenValidationParameters.ValidateAudience = false;
 17→            // Disable HTTPS metadata validation -- K8s cluster runs Keycloak over HTTP internally.
 18→            options.RequireHttpsMetadata = false;
 19→        });
 20→
 21→// Authorization policies
 22→builder.Services.AddAuthorizationBuilder()
 23→    .AddPolicy("authenticated", policy => policy.RequireAuthenticatedUser());
 24→
 25→// CORS policy - centralized at gateway level, configurable via Cors:Origins
 26→string[] corsOrigins = builder.Configuration.GetSection("Cors:Origins").Get<string[]>()
 27→    ?? ["http://localhost:3000", "http://localhost:3001"];
 28→builder.Services.AddCors(options =>
 29→{
 30→    options.AddDefaultPolicy(policy =>
 31→    {
 32→        policy.WithOrigins(corsOrigins)
 33→            .AllowAnyHeader()
 34→            .AllowAnyMethod()
 35→            .AllowCredentials();
 36→    });
 37→});
 38→
 39→// Rate limiting - partitioned sliding window (authenticated vs anonymous)
 40→builder.Services.AddRateLimiter(options =>
 41→{
 42→    options.OnRejected = async (context, token) =>
 43→    {
 44→        context.HttpContext.Response.StatusCode = 429;
 45→        if (context.Lease.TryGetMetadata(MetadataName.RetryAfter, out var retryAfter))
 46→        {
 47→            context.HttpContext.Response.Headers.RetryAfter =
 48→                ((int)retryAfter.TotalSeconds).ToString();
 49→        }
 50→        await context.HttpContext.Response.WriteAsync("Too many requests", token);
 51→    };
 52→
 53→    options.GlobalLimiter = PartitionedRateLimiter.Create<HttpContext, string>(httpContext =>
 54→    {
 55→        var userName = httpContext.User.Identity?.Name;
 56→        return string.IsNullOrEmpty(userName)
 57→            ? RateLimitPartition.GetSlidingWindowLimiter(
 58→                httpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown",
 59→                _ => new SlidingWindowRateLimiterOptions
 60→                {
 61→                    PermitLimit = 30,
 62→                    Window = TimeSpan.FromMinutes(1),
 63→                    SegmentsPerWindow = 6,
 64→                    QueueLimit = 0
 65→                })
 66→            : RateLimitPartition.GetSlidingWindowLimiter(userName, _ =>
 67→                new SlidingWindowRateLimiterOptions
 68→                {
 69→                    PermitLimit = 100,
 70→                    Window = TimeSpan.FromMinutes(1),
 71→                    SegmentsPerWindow = 6,
 72→                    QueueLimit = 0
 73→                });
 74→    });
 75→});
 76→
 77→// YARP reverse proxy
 78→builder.Services.AddReverseProxy()
 79→    .LoadFromConfig(builder.Configuration.GetSection("ReverseProxy"));
 80→
 81→var app = builder.Build();
 82→
 83→// Middleware pipeline - ORDER MATTERS
 84→app.UseCors();
 85→app.UseRateLimiter();
 86→
 87→// Add X-Request-ID header to all requests
 88→app.Use(async (context, next) =>
 89→{
 90→    if (!context.Request.Headers.ContainsKey("X-Request-ID"))
 91→    {
 92→        context.Request.Headers.Append("X-Request-ID",
 93→            Activity.Current?.Id ?? Guid.NewGuid().ToString());
 94→    }
 95→    await next();
 96→});
 97→
 98→app.UseAuthentication();
 99→app.UseAuthorization();
100→app.MapReverseProxy();
101→app.MapDefaultEndpoints();
102→
103→app.Run();
104→

