 33→export function useAddToCart() {
 34→  const queryClient = useQueryClient();
 35→
 36→  return useMutation({
 37→    mutationFn: (data: AddToCartRequest) => addToCart(data),
 38→    onSuccess: (response) => {
 39→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
 40→      toast.success(response.isUpdate ? "Updated quantity" : "Added to cart");
 41→    },
 42→    onError: () => {
