 48→export function useUpdateCartItem() {
 49→  const queryClient = useQueryClient();
 50→
 51→  return useMutation({
 52→    mutationFn: ({ itemId, quantity }: { itemId: string; quantity: number }) =>
 53→      updateCartItemQuantity(itemId, quantity),
 54→    onMutate: async ({ itemId, quantity }) => {
 55→      await queryClient.cancelQueries({ queryKey: CART_QUERY_KEY });
 56→
 57→      const previousCart = queryClient.getQueryData<CartDto | null>(
 58→        CART_QUERY_KEY
 59→      );
 60→
 61→      queryClient.setQueryData<CartDto | null>(CART_QUERY_KEY, (old) => {
 62→        if (!old) return old;
 63→        return {
 64→          ...old,
 65→          items: old.items.map((item) =>
 66→            item.id === itemId
 67→              ? {
 68→                  ...item,
 69→                  quantity,
 70→                  lineTotal: item.unitPrice * quantity,
 71→                }
 72→              : item
 73→          ),
 74→          totalPrice: old.items.reduce(
 75→            (sum, item) =>
 76→              sum +
 77→              (item.id === itemId
 78→                ? item.unitPrice * quantity
 79→                : item.lineTotal),
 80→            0
 81→          ),
 82→          totalItems: old.items.reduce(
 83→            (sum, item) =>
 84→              sum + (item.id === itemId ? quantity : item.quantity),
 85→            0
 86→          ),
 87→        };
 88→      });
 89→
 90→      return { previousCart };
 91→    },
 92→    onError: (_err, _vars, context) => {
 93→      if (context?.previousCart !== undefined) {
 94→        queryClient.setQueryData(CART_QUERY_KEY, context.previousCart);
 95→      }
 96→      toast.error("Failed to update quantity");
 97→    },
 98→    onSettled: () => {
 99→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
100→    },
101→  });
102→}
