104→export function useRemoveCartItem() {
105→  const queryClient = useQueryClient();
106→
107→  return useMutation({
108→    mutationFn: (itemId: string) => removeCartItem(itemId),
109→    onMutate: async (itemId) => {
110→      await queryClient.cancelQueries({ queryKey: CART_QUERY_KEY });
111→
112→      const previousCart = queryClient.getQueryData<CartDto | null>(
113→        CART_QUERY_KEY
114→      );
115→
116→      queryClient.setQueryData<CartDto | null>(CART_QUERY_KEY, (old) => {
117→        if (!old) return old;
118→        const removedItem = old.items.find((item) => item.id === itemId);
119→        const filteredItems = old.items.filter((item) => item.id !== itemId);
120→        return {
121→          ...old,
122→          items: filteredItems,
123→          totalPrice: old.totalPrice - (removedItem?.lineTotal ?? 0),
124→          totalItems: old.totalItems - (removedItem?.quantity ?? 0),
125→        };
126→      });
127→
128→      return { previousCart };
129→    },
130→    onError: (_err, _vars, context) => {
131→      if (context?.previousCart !== undefined) {
132→        queryClient.setQueryData(CART_QUERY_KEY, context.previousCart);
133→      }
134→      toast.error("Failed to remove item");
135→    },
136→    onSettled: () => {
137→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
138→    },
139→  });
140→}
